void LidarCenterPointNode::pointCloudCallback(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & input_pointcloud_msg)
{
  const auto objects_sub_count =
    objects_pub_->get_subscription_count() + objects_pub_->get_intra_process_subscription_count();
  if (objects_sub_count < 1) {
    return;
  }

  if (stop_watch_ptr_) {
    stop_watch_ptr_->toc("processing_time", true);
  }
  diagnostics_centerpoint_trt_->clear();

  std::vector<Box3D> det_boxes3d;
  bool is_num_pillars_within_range = true;
  bool is_success = detector_ptr_->detect(
    input_pointcloud_msg, tf_buffer_, det_boxes3d, is_num_pillars_within_range);
  if (!is_success) {
    return;
  }
  diagnostics_centerpoint_trt_->add_key_value(
    "is_num_pillars_within_range", is_num_pillars_within_range);
  if (!is_num_pillars_within_range) {
    std::stringstream message;
    message << "CenterPointTRT::detect: The actual number of pillars exceeds its maximum value, "
            << "which may limit the detection performance.";
    diagnostics_centerpoint_trt_->update_level_and_message(
      diagnostic_msgs::msg::DiagnosticStatus::WARN, message.str());
  }

  std::vector<autoware_perception_msgs::msg::DetectedObject> raw_objects;
  raw_objects.reserve(det_boxes3d.size());
  for (const auto & box3d : det_boxes3d) {
    autoware_perception_msgs::msg::DetectedObject obj;
    box3DToDetectedObject(box3d, class_names_, has_twist_, has_variance_, obj);
    raw_objects.emplace_back(obj);
  }

  autoware_perception_msgs::msg::DetectedObjects output_msg;
  output_msg.header = input_pointcloud_msg->header;
  output_msg.objects = iou_bev_nms_.apply(raw_objects);

  detection_class_remapper_.mapClasses(output_msg);

  if (objects_sub_count > 0) {
    objects_pub_->publish(output_msg);
    published_time_publisher_->publish_if_subscribed(objects_pub_, output_msg.header.stamp);
  }
  diagnostics_centerpoint_trt_->publish(input_pointcloud_msg->header.stamp);

  // add processing time for debug
  if (debug_publisher_ptr_ && stop_watch_ptr_) {
    const double cyclic_time_ms = stop_watch_ptr_->toc("cyclic_time", true);
    const double processing_time_ms = stop_watch_ptr_->toc("processing_time", true);
    const double pipeline_latency_ms =
      std::chrono::duration<double, std::milli>(
        std::chrono::nanoseconds(
          (this->get_clock()->now() - output_msg.header.stamp).nanoseconds()))
        .count();
    debug_publisher_ptr_->publish<autoware_internal_debug_msgs::msg::Float64Stamped>(
      "debug/cyclic_time_ms", cyclic_time_ms);
    debug_publisher_ptr_->publish<autoware_internal_debug_msgs::msg::Float64Stamped>(
      "debug/processing_time_ms", processing_time_ms);
    debug_publisher_ptr_->publish<autoware_internal_debug_msgs::msg::Float64Stamped>(
      "debug/pipeline_latency_ms", pipeline_latency_ms);

    last_processing_time_ms_ = processing_time_ms;
  }
}

bool CenterPointTRT::detect(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & input_pointcloud_msg_ptr,
  const tf2_ros::Buffer & tf_buffer, std::vector<Box3D> & det_boxes3d,
  bool & is_num_pillars_within_range)
{
  is_num_pillars_within_range = true;

  CHECK_CUDA_ERROR(cudaMemsetAsync(
    encoder_in_features_d_.get(), 0, encoder_in_feature_size_ * sizeof(float), stream_));
  CHECK_CUDA_ERROR(
    cudaMemsetAsync(spatial_features_d_.get(), 0, spatial_features_size_ * sizeof(float), stream_));

  if (!preprocess(input_pointcloud_msg_ptr, tf_buffer)) {
    RCLCPP_WARN(
      rclcpp::get_logger(config_.logger_name_.c_str()), "Fail to preprocess and skip to detect.");
    return false;
  }

  inference();

  postProcess(det_boxes3d);

  // Check the actual number of pillars after inference to avoid unnecessary synchronization.
  unsigned int num_pillars = 0;
  CHECK_CUDA_ERROR(
    cudaMemcpy(&num_pillars, num_voxels_d_.get(), sizeof(unsigned int), cudaMemcpyDeviceToHost));

  if (num_pillars >= config_.max_voxel_size_) {
    rclcpp::Clock clock{RCL_ROS_TIME};
    RCLCPP_WARN_THROTTLE(
      rclcpp::get_logger(config_.logger_name_.c_str()), clock, 1000,
      "The actual number of pillars (%u) exceeds its maximum value (%zu). "
      "Please considering increasing it since it may limit the detection performance.",
      num_pillars, config_.max_voxel_size_);
    is_num_pillars_within_range = false;
  }

  return true;
}

bool CenterPointTRT::preprocess(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & input_pointcloud_msg_ptr,
  const tf2_ros::Buffer & tf_buffer)
{
  using autoware::cuda_utils::clear_async;

  bool is_success = vg_ptr_->enqueuePointCloud(input_pointcloud_msg_ptr, tf_buffer);
  if (!is_success) {
    return false;
  }

  const auto points_capacity_size = config_.cloud_capacity_ * config_.point_feature_size_;
  clear_async(points_aux_d_.get(), points_capacity_size, stream_);
  clear_async(points_d_.get(), points_capacity_size, stream_);
  clear_async(num_voxels_d_.get(), 1, stream_);
  clear_async(voxels_buffer_d_.get(), voxels_buffer_size_, stream_);
  clear_async(mask_d_.get(), mask_size_, stream_);
  clear_async(voxels_d_.get(), voxels_size_, stream_);
  clear_async(coordinates_d_.get(), coordinates_size_, stream_);
  clear_async(num_points_per_voxel_d_.get(), config_.max_voxel_size_, stream_);

  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));

  const std::size_t count = vg_ptr_->generateSweepPoints(points_aux_d_.get());
  const std::size_t random_offset = std::rand() % config_.cloud_capacity_;

  pre_proc_ptr_->shufflePoints_launch(
    points_aux_d_.get(), shuffle_indices_d_.get(), points_d_.get(), count, config_.cloud_capacity_,
    random_offset);

  pre_proc_ptr_->generateVoxels_random_launch(
    points_d_.get(), config_.cloud_capacity_, mask_d_.get(), voxels_buffer_d_.get());

  pre_proc_ptr_->generateBaseFeatures_launch(
    mask_d_.get(), voxels_buffer_d_.get(), num_voxels_d_.get(), voxels_d_.get(),
    num_points_per_voxel_d_.get(), coordinates_d_.get());

  pre_proc_ptr_->generateFeatures_launch(
    voxels_d_.get(), num_points_per_voxel_d_.get(), coordinates_d_.get(), num_voxels_d_.get(),
    encoder_in_features_d_.get());

  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));
  return true;
}

bool VoxelGeneratorTemplate::enqueuePointCloud(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & input_pointcloud_msg_ptr,
  const tf2_ros::Buffer & tf_buffer)
{
  return pd_ptr_->enqueuePointCloud(input_pointcloud_msg_ptr, tf_buffer);
}

bool PointCloudDensification::enqueuePointCloud(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & pointcloud_msg_ptr,
  const tf2_ros::Buffer & tf_buffer)
{
  const auto header = pointcloud_msg_ptr->header;

  if (param_.pointcloud_cache_size() > 1) {
    auto transform_world2current = getTransform(
      tf_buffer, header.frame_id, param_.world_frame_id(), header.stamp, param_.logger_name());
    if (!transform_world2current) {
      return false;
    }
    auto affine_world2current = transformToEigen(transform_world2current.get());

    enqueue(pointcloud_msg_ptr, affine_world2current);
  } else {
    enqueue(pointcloud_msg_ptr, Eigen::Affine3f::Identity());
  }

  dequeue();

  return true;
}

boost::optional<geometry_msgs::msg::Transform> getTransform(
  const tf2_ros::Buffer & tf_buffer, const std::string & target_frame_id,
  const std::string & source_frame_id, const rclcpp::Time & time, const std::string & logger_name)
{
  try {
    geometry_msgs::msg::TransformStamped transform_stamped;
    transform_stamped = tf_buffer.lookupTransform(
      target_frame_id, source_frame_id, time, rclcpp::Duration::from_seconds(0.5));
    return transform_stamped.transform;
  } catch (tf2::TransformException & ex) {
    RCLCPP_WARN_STREAM(rclcpp::get_logger(logger_name.c_str()), ex.what());
    return boost::none;
  }
}

Eigen::Affine3f transformToEigen(const geometry_msgs::msg::Transform & t)
{
  Eigen::Affine3f a;
  a.matrix() = tf2::transformToEigen(t).matrix().cast<float>();
  return a;
}

void PointCloudDensification::enqueue(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & msg_ptr,
  const Eigen::Affine3f & affine_world2current)
{
  affine_world2current_ = affine_world2current;
  current_timestamp_ = rclcpp::Time(msg_ptr->header.stamp).seconds();
  PointCloudWithTransform pointcloud = {msg_ptr, affine_world2current.inverse()};
  pointcloud_cache_.push_front(pointcloud);
}

void PointCloudDensification::dequeue()
{
  if (pointcloud_cache_.size() > param_.pointcloud_cache_size()) {
    pointcloud_cache_.pop_back();
  }
}

std::size_t VoxelGenerator::generateSweepPoints(float * points_d)
{
  std::size_t point_counter = 0;
  for (auto pc_cache_iter = pd_ptr_->getPointCloudCacheIter(); !pd_ptr_->isCacheEnd(pc_cache_iter);
       pc_cache_iter++) {
    const auto & input_pointcloud_msg_ptr = pc_cache_iter->input_pointcloud_msg_ptr;
    auto sweep_num_points = input_pointcloud_msg_ptr->height * input_pointcloud_msg_ptr->width;
    auto output_offset = point_counter * config_.point_feature_size_;
    auto affine_past2current =
      pd_ptr_->getAffineWorldToCurrent() * pc_cache_iter->affine_past2world;
    float time_lag = static_cast<float>(
      pd_ptr_->getCurrentTimestamp() -
      rclcpp::Time(input_pointcloud_msg_ptr->header.stamp).seconds());

    if (point_counter + sweep_num_points > config_.cloud_capacity_) {
      RCLCPP_WARN_STREAM(
        rclcpp::get_logger(config_.logger_name_.c_str()),
        "Requested number of points exceeds the maximum capacity. Current points = "
          << point_counter);
      break;
    }

    static_assert(std::is_same<decltype(affine_past2current.matrix()), Eigen::Matrix4f &>::value);
    static_assert(!Eigen::Matrix4f::IsRowMajor, "matrices should be col-major.");

    CHECK_CUDA_ERROR(cudaMemcpyAsync(
      affine_past2current_d_.get(), affine_past2current.data(), AFF_MAT_SIZE * sizeof(float),
      cudaMemcpyHostToDevice, stream_));
    CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));

    pre_ptr_->generateSweepPoints_launch(
      reinterpret_cast<InputPointType *>(input_pointcloud_msg_ptr->data.get()), sweep_num_points,
      time_lag, affine_past2current_d_.get(), points_d + output_offset);

    point_counter += sweep_num_points;
  }
  return point_counter;
}

std::list<PointCloudWithTransform>::iterator getPointCloudCacheIter()
{
  return pointcloud_cache_.begin();
}

cudaError_t PreprocessCuda::generateSweepPoints_launch(
  const InputPointType * input_points, std::size_t points_size, float time_lag,
  const float * transform_array, float * output_points)
{
  dim3 blocks((points_size + 256 - 1) / 256);
  dim3 threads(256);

  if (config_.point_feature_size_ == POINT_DIM_XYZT) {
    generateSweepPoints_kernel<POINT_DIM_XYZT><<<blocks, threads, 0, stream_>>>(
      input_points, points_size, time_lag, transform_array, output_points);
  } else if (config_.point_feature_size_ == POINT_DIM_XYZIT) {
    generateSweepPoints_kernel<POINT_DIM_XYZIT><<<blocks, threads, 0, stream_>>>(
      input_points, points_size, time_lag, transform_array, output_points);
  } else {
    throw std::runtime_error("Value of point_features_size is not supported!");
  }

  cudaError_t err = cudaGetLastError();
  return err;
}

__global__ void generateSweepPoints_kernel(
  const InputPointType * __restrict__ input_points, std::size_t points_size, float time_lag,
  const float * transform_array, float * __restrict__ output_points)
{
  int point_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (point_idx >= points_size) return;

  const InputPointType * input_point = &input_points[point_idx];
  float input_x = input_point->x;
  float input_y = input_point->y;
  float input_z = input_point->z;

  output_points[point_idx * POINT_NUM_FEATURES] =
    transform_array[0] * input_x + transform_array[4] * input_y + transform_array[8] * input_z +
    transform_array[12];
  output_points[point_idx * POINT_NUM_FEATURES + 1] =
    transform_array[1] * input_x + transform_array[5] * input_y + transform_array[9] * input_z +
    transform_array[13];
  output_points[point_idx * POINT_NUM_FEATURES + 2] =
    transform_array[2] * input_x + transform_array[6] * input_y + transform_array[10] * input_z +
    transform_array[14];

  // Time_lag
  if (POINT_NUM_FEATURES == POINT_DIM_XYZT) {
    output_points[point_idx * POINT_NUM_FEATURES + 3] = time_lag;
    // Intensity & time_lag
  } else {
    auto input_intensity = static_cast<float>(input_point->intensity);
    output_points[point_idx * POINT_NUM_FEATURES + 3] = input_intensity;
    output_points[point_idx * POINT_NUM_FEATURES + 4] = time_lag;
  }
}

__global__ void generateSweepPoints_kernel(
  const InputPointType * __restrict__ input_points, std::size_t points_size, float time_lag,
  const float * transform_array, float * __restrict__ output_points)
{
  int point_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (point_idx >= points_size) return;

  const InputPointType * input_point = &input_points[point_idx];
  float input_x = input_point->x;
  float input_y = input_point->y;
  float input_z = input_point->z;

  output_points[point_idx * POINT_NUM_FEATURES] =
    transform_array[0] * input_x + transform_array[4] * input_y + transform_array[8] * input_z +
    transform_array[12];
  output_points[point_idx * POINT_NUM_FEATURES + 1] =
    transform_array[1] * input_x + transform_array[5] * input_y + transform_array[9] * input_z +
    transform_array[13];
  output_points[point_idx * POINT_NUM_FEATURES + 2] =
    transform_array[2] * input_x + transform_array[6] * input_y + transform_array[10] * input_z +
    transform_array[14];

  // Time_lag
  if (POINT_NUM_FEATURES == POINT_DIM_XYZT) {
    output_points[point_idx * POINT_NUM_FEATURES + 3] = time_lag;
    // Intensity & time_lag
  } else {
    auto input_intensity = static_cast<float>(input_point->intensity);
    output_points[point_idx * POINT_NUM_FEATURES + 3] = input_intensity;
    output_points[point_idx * POINT_NUM_FEATURES + 4] = time_lag;
  }
}

cudaError_t PreprocessCuda::shufflePoints_launch(
  const float * points, const unsigned int * indices, float * shuffled_points,
  const std::size_t points_size, const std::size_t max_size, const std::size_t offset)
{
  dim3 blocks((max_size + 256 - 1) / 256);
  dim3 threads(256);

  if (blocks.x == 0) {
    return cudaGetLastError();
  }

  if (config_.point_feature_size_ == POINT_DIM_XYZT) {
    shufflePoints_kernel<POINT_DIM_XYZT><<<blocks, threads, 0, stream_>>>(
      points, indices, shuffled_points, points_size, max_size, offset);
  } else if (config_.point_feature_size_ == POINT_DIM_XYZIT) {
    shufflePoints_kernel<POINT_DIM_XYZIT><<<blocks, threads, 0, stream_>>>(
      points, indices, shuffled_points, points_size, max_size, offset);
  } else {
    throw std::runtime_error("Value of point_features_size is not supported!");
  }
  cudaError_t err = cudaGetLastError();
  return err;
}

__global__ void shufflePoints_kernel(
  const float * points, const unsigned int * indices, float * shuffled_points,
  const std::size_t points_size, const std::size_t max_size, const std::size_t offset)
{
  int point_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (point_idx >= max_size) return;

  int src_idx = indices[(point_idx + offset) % max_size];
  int dst_idx = point_idx;

  if (src_idx >= points_size) {
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 0] = INFINITY;
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 1] = INFINITY;
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 2] = INFINITY;
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 3] = INFINITY;
    if (POINT_NUM_FEATURES == POINT_DIM_XYZIT) {
      shuffled_points[POINT_NUM_FEATURES * dst_idx + 4] = INFINITY;
    }
  } else {
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 0] = points[POINT_NUM_FEATURES * src_idx + 0];
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 1] = points[POINT_NUM_FEATURES * src_idx + 1];
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 2] = points[POINT_NUM_FEATURES * src_idx + 2];
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 3] = points[POINT_NUM_FEATURES * src_idx + 3];
    if (POINT_NUM_FEATURES == POINT_DIM_XYZIT) {
      shuffled_points[POINT_NUM_FEATURES * dst_idx + 4] = points[POINT_NUM_FEATURES * src_idx + 4];
    }
  }
}

__global__ void shufflePoints_kernel(
  const float * points, const unsigned int * indices, float * shuffled_points,
  const std::size_t points_size, const std::size_t max_size, const std::size_t offset)
{
  int point_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (point_idx >= max_size) return;

  int src_idx = indices[(point_idx + offset) % max_size];
  int dst_idx = point_idx;

  if (src_idx >= points_size) {
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 0] = INFINITY;
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 1] = INFINITY;
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 2] = INFINITY;
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 3] = INFINITY;
    if (POINT_NUM_FEATURES == POINT_DIM_XYZIT) {
      shuffled_points[POINT_NUM_FEATURES * dst_idx + 4] = INFINITY;
    }
  } else {
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 0] = points[POINT_NUM_FEATURES * src_idx + 0];
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 1] = points[POINT_NUM_FEATURES * src_idx + 1];
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 2] = points[POINT_NUM_FEATURES * src_idx + 2];
    shuffled_points[POINT_NUM_FEATURES * dst_idx + 3] = points[POINT_NUM_FEATURES * src_idx + 3];
    if (POINT_NUM_FEATURES == POINT_DIM_XYZIT) {
      shuffled_points[POINT_NUM_FEATURES * dst_idx + 4] = points[POINT_NUM_FEATURES * src_idx + 4];
    }
  }
}

cudaError_t PreprocessCuda::generateFeatures_launch(
  const float * voxel_features, const float * voxel_num_points, const int * coords,
  const unsigned int * num_voxels, float * features)
{
  dim3 blocks(divup(config_.max_voxel_size_, WARPS_PER_BLOCK));
  dim3 threads(WARPS_PER_BLOCK * MAX_POINT_IN_VOXEL_SIZE);
  if (config_.encoder_in_feature_size_ == ENCODER_NUM_FEATURES_9) {
    generateFeatures_kernel<ENCODER_NUM_FEATURES_9><<<blocks, threads, 0, stream_>>>(
      voxel_features, voxel_num_points, coords, num_voxels, config_.voxel_size_x_,
      config_.voxel_size_y_, config_.voxel_size_z_, config_.range_min_x_, config_.range_min_y_,
      config_.range_min_z_, features);
  } else if (config_.encoder_in_feature_size_ == ENCODER_NUM_FEATURES_10) {
    generateFeatures_kernel<ENCODER_NUM_FEATURES_10><<<blocks, threads, 0, stream_>>>(
      voxel_features, voxel_num_points, coords, num_voxels, config_.voxel_size_x_,
      config_.voxel_size_y_, config_.voxel_size_z_, config_.range_min_x_, config_.range_min_y_,
      config_.range_min_z_, features);
  } else if (config_.encoder_in_feature_size_ == ENCODER_NUM_FEATURES_11) {
    generateFeatures_kernel<ENCODER_NUM_FEATURES_11><<<blocks, threads, 0, stream_>>>(
      voxel_features, voxel_num_points, coords, num_voxels, config_.voxel_size_x_,
      config_.voxel_size_y_, config_.voxel_size_z_, config_.range_min_x_, config_.range_min_y_,
      config_.range_min_z_, features);
  } else {
    throw std::runtime_error("Value of encoder_in_feature_size is not supported!");
  }

  return cudaGetLastError();
}

__global__ void generateFeatures_kernel(
  const float * voxel_features, const float * voxel_num_points, const int * coords,
  const unsigned int * num_voxels, const float voxel_x, const float voxel_y, const float voxel_z,
  const float range_min_x, const float range_min_y, const float range_min_z, float * features)
{
  // voxel_features (float): (max_voxel_size, max_point_in_voxel_size, point_feature_size)
  // voxel_num_points (int): (max_voxel_size)
  // coords (int): (max_voxel_size, point_dim_size)
  int pillar_idx = blockIdx.x * WARPS_PER_BLOCK + threadIdx.x / MAX_POINT_IN_VOXEL_SIZE;
  int point_idx = threadIdx.x % MAX_POINT_IN_VOXEL_SIZE;
  int pillar_idx_inBlock = threadIdx.x / MAX_POINT_IN_VOXEL_SIZE;  // max_point_in_voxel_size

  unsigned int num_pillars = num_voxels[0];
  if (pillar_idx >= num_pillars) return;

  // point dimemension is 5 if feature size in encoder is 11, otherwise 4
  constexpr int point_dim =
    (ENCODER_IN_FEATURE_SIZE >= ENCODER_NUM_FEATURES_11) ? POINT_DIM_XYZIT : POINT_DIM_XYZT;

  // load src
  __shared__ float pillarSM[WARPS_PER_BLOCK][MAX_POINT_IN_VOXEL_SIZE][point_dim];
  __shared__ float3 pillarSumSM[WARPS_PER_BLOCK];
  __shared__ int3 cordsSM[WARPS_PER_BLOCK];
  __shared__ int pointsNumSM[WARPS_PER_BLOCK];
  __shared__ float pillarOutSM[WARPS_PER_BLOCK][MAX_POINT_IN_VOXEL_SIZE][ENCODER_IN_FEATURE_SIZE];

  if (threadIdx.x < WARPS_PER_BLOCK) {
    pointsNumSM[threadIdx.x] = voxel_num_points[blockIdx.x * WARPS_PER_BLOCK + threadIdx.x];
    cordsSM[threadIdx.x] = ((int3 *)coords)[blockIdx.x * WARPS_PER_BLOCK + threadIdx.x];
    pillarSumSM[threadIdx.x] = {0, 0, 0};
  }

#pragma unroll
  for (int i = 0; i < point_dim; i++) {
    int pillarSMId = pillar_idx_inBlock * MAX_POINT_IN_VOXEL_SIZE * point_dim +
                     i * MAX_POINT_IN_VOXEL_SIZE + point_idx;
    int voxel_feature_id =
      pillar_idx * MAX_POINT_IN_VOXEL_SIZE * point_dim + i * MAX_POINT_IN_VOXEL_SIZE + point_idx;
    ((float *)pillarSM)[pillarSMId] = ((float *)voxel_features)[voxel_feature_id];
  }
  __syncthreads();

  // calculate sm in a pillar
  if (point_idx < pointsNumSM[pillar_idx_inBlock]) {
    atomicAdd(&(pillarSumSM[pillar_idx_inBlock].x), pillarSM[pillar_idx_inBlock][point_idx][0]);
    atomicAdd(&(pillarSumSM[pillar_idx_inBlock].y), pillarSM[pillar_idx_inBlock][point_idx][1]);
    atomicAdd(&(pillarSumSM[pillar_idx_inBlock].z), pillarSM[pillar_idx_inBlock][point_idx][2]);
  }
  __syncthreads();

  // feature-mean
  float3 mean;
  float validPoints = pointsNumSM[pillar_idx_inBlock];
