void CenterPointTRT::inference()
{
  // pillar encoder network
  std::vector<void *> encoder_tensors = {encoder_in_features_d_.get(), pillar_features_d_.get()};
  encoder_trt_ptr_->setTensorsAddresses(encoder_tensors);
  encoder_trt_ptr_->enqueueV3(stream_);

  // scatter
  CHECK_CUDA_ERROR(scatterFeatures_launch(
    pillar_features_d_.get(), coordinates_d_.get(), num_voxels_d_.get(), config_.max_voxel_size_,
    config_.encoder_out_feature_size_, config_.grid_size_x_, config_.grid_size_y_,
    spatial_features_d_.get(), stream_));

  // head network
  std::vector<void *> head_tensors = {spatial_features_d_.get(), head_out_heatmap_d_.get(),
                                      head_out_offset_d_.get(),  head_out_z_d_.get(),
                                      head_out_dim_d_.get(),     head_out_rot_d_.get(),
                                      head_out_vel_d_.get()};
  head_trt_ptr_->setTensorsAddresses(head_tensors);

  head_trt_ptr_->enqueueV3(stream_);
}

bool TrtCommon::setTensorsAddresses(std::vector<void *> & tensors)
{
  bool success = true;
  for (std::size_t i = 0, e = tensors.size(); i < e; i++) {
    auto const name = getIOTensorName(i);
    success &= setTensorAddress(name, tensors.at(i));
  }
  return success;
}

const char * TrtCommon::getIOTensorName(const int32_t index) const
{
  if (!engine_) {
    logger_->log(
      nvinfer1::ILogger::Severity::kWARNING,
      "Engine is not initialized. Retrieving data from network");
    if (!network_) {
      logger_->log(nvinfer1::ILogger::Severity::kERROR, "Network is not initialized");
      return nullptr;
    }
    auto num_inputs = network_->getNbInputs();
    auto num_outputs = network_->getNbOutputs();
    if (index < 0 || index >= num_inputs + num_outputs) {
      logger_->log(
        nvinfer1::ILogger::Severity::kERROR,
        "Invalid index for I/O tensor: %d. Total I/O tensors: %d", index, num_inputs + num_outputs);
      return nullptr;
    }
    if (index < num_inputs) {
      return network_->getInput(index)->getName();
    }
    return network_->getOutput(index - num_inputs)->getName();
  }

  return engine_->getIOTensorName(index);
}

