    RCLCPP_DEBUG_STREAM(rclcpp::get_logger(config_.logger_name_.c_str()), "No detected boxes.");
  }
}

cudaError_t PostProcessCUDA::generateDetectedBoxes3D_launch(
  const float * out_heatmap, const float * out_offset, const float * out_z, const float * out_dim,
  const float * out_rot, const float * out_vel, std::vector<Box3D> & det_boxes3d,
  cudaStream_t stream)
{
  dim3 blocks(
    divup(config_.down_grid_size_y_, THREADS_PER_BLOCK),
    divup(config_.down_grid_size_x_, THREADS_PER_BLOCK));
  dim3 threads(THREADS_PER_BLOCK, THREADS_PER_BLOCK);
  auto boxes3d_d =
    thrust::device_vector<Box3D>(config_.down_grid_size_y_ * config_.down_grid_size_x_);
  auto yaw_norm_thresholds_d = thrust::device_vector<float>(
    config_.yaw_norm_thresholds_.begin(), config_.yaw_norm_thresholds_.end());
  generateBoxes3D_kernel<<<blocks, threads, 0, stream>>>(
    out_heatmap, out_offset, out_z, out_dim, out_rot, out_vel, config_.voxel_size_x_,
    config_.voxel_size_y_, config_.range_min_x_, config_.range_min_y_, config_.down_grid_size_x_,
    config_.down_grid_size_y_, config_.downsample_factor_, config_.class_size_,
    distance_bin_upper_limits_d_ptr_.get(), score_thresholds_d_ptr_.get(),
    config_.distance_bin_upper_limits_.size(), config_.has_variance_,
    thrust::raw_pointer_cast(yaw_norm_thresholds_d.data()),
    thrust::raw_pointer_cast(boxes3d_d.data()));

  // suppress by score
  const auto num_det_boxes3d =
    thrust::count_if(thrust::device, boxes3d_d.begin(), boxes3d_d.end(), is_score_keep());
  if (num_det_boxes3d == 0) {
    return cudaGetLastError();
  }
  thrust::device_vector<Box3D> det_boxes3d_d(num_det_boxes3d);
  thrust::copy_if(
    thrust::device, boxes3d_d.begin(), boxes3d_d.end(), det_boxes3d_d.begin(), is_score_keep());

  // sort by score
  thrust::sort(det_boxes3d_d.begin(), det_boxes3d_d.end(), score_greater());

  // supress by NMS
  thrust::device_vector<bool> final_keep_mask_d(num_det_boxes3d);
  const auto num_final_det_boxes3d =
    circleNMS(det_boxes3d_d, config_.circle_nms_dist_threshold_, final_keep_mask_d, stream);

  thrust::device_vector<Box3D> final_det_boxes3d_d(num_final_det_boxes3d);
  thrust::copy_if(
    thrust::device, det_boxes3d_d.begin(), det_boxes3d_d.end(), final_keep_mask_d.begin(),
    final_det_boxes3d_d.begin(), is_kept());

  // memcpy device to host
  det_boxes3d.resize(num_final_det_boxes3d);
  thrust::copy(final_det_boxes3d_d.begin(), final_det_boxes3d_d.end(), det_boxes3d.begin());

  return cudaGetLastError();
}

__global__ void generateBoxes3D_kernel(
  const float * out_heatmap, const float * out_offset, const float * out_z, const float * out_dim,
  const float * out_rot, const float * out_vel, const float voxel_size_x, const float voxel_size_y,
  const float range_min_x, const float range_min_y, const std::size_t down_grid_size_x,
  const std::size_t down_grid_size_y, const std::size_t downsample_factor, const int class_size,
  const float * distance_bin_upper_limits, const float * score_thresholds,
  const std::size_t num_distance_bin_upper_limits, const bool has_variance,
  const float * yaw_norm_thresholds, Box3D * det_boxes3d)
{
  // generate boxes3d from the outputs of the network.
  // shape of out_*: (N, DOWN_GRID_SIZE_Y, DOWN_GRID_SIZE_X)
  // heatmap: N = class_size, offset: N = 2, z: N = 1, dim: N = 3, rot: N = 2, vel: N = 2
  const auto yi = blockIdx.x * THREADS_PER_BLOCK + threadIdx.x;
  const auto xi = blockIdx.y * THREADS_PER_BLOCK + threadIdx.y;
  const auto idx = down_grid_size_x * yi + xi;
  const auto down_grid_size = down_grid_size_y * down_grid_size_x;

  if (yi >= down_grid_size_y || xi >= down_grid_size_x) {
    return;
  }

  int label = -1;
  float max_score = -1;
  for (int ci = 0; ci < class_size; ci++) {
    float score = sigmoid(out_heatmap[down_grid_size * ci + idx]);
    if (score > max_score) {
      label = ci;
      max_score = score;
    }
  }

  // If the label is not found, then we set the score to 0, and stop processing
  if (label == -1) {
    det_boxes3d[idx].score = 0.f;
    return;
  }

  const float offset_x = out_offset[down_grid_size * 0 + idx];
  const float offset_y = out_offset[down_grid_size * 1 + idx];
  const float x = voxel_size_x * downsample_factor * (xi + offset_x) + range_min_x;
  const float y = voxel_size_y * downsample_factor * (yi + offset_y) + range_min_y;
  const float radial_distance = sqrtf(x * x + y * y);
  // Loop through score_upper_bounds to decide the distance bucket index, and since upper_bounds is
  // sorted in ascending order, the first one that is greater than the radial distance is the
  // distance bucket index
  int distance_bucket_index = -1;
  for (int i = 0; i < num_distance_bin_upper_limits; i++) {
    if (radial_distance < distance_bin_upper_limits[i]) {
      distance_bucket_index = i;
      break;
    }
  }

  // If the radial distance is greater than the last distance_bin_upper_limit, which is out of bound
  // and then we set the score to 0, and stop processing
  if (distance_bucket_index == -1) {
    det_boxes3d[idx].score = 0.f;
    return;
  }

  // Index = distance_bucket_index * class_size + label since row = num of distance buckets and
  // column = num of classes
  const float class_score_threshold = score_thresholds[distance_bucket_index * class_size + label];

  // If the score is less than the class score threshold, then we set the score to 0, and stop
  // processing
  if (max_score < class_score_threshold) {
    det_boxes3d[idx].score = 0.f;
    return;
  }

  const float z = out_z[idx];
  const float w = out_dim[down_grid_size * 0 + idx];
  const float l = out_dim[down_grid_size * 1 + idx];
  const float h = out_dim[down_grid_size * 2 + idx];
  const float yaw_sin = out_rot[down_grid_size * 0 + idx];
  const float yaw_cos = out_rot[down_grid_size * 1 + idx];
  const float yaw_norm = sqrtf(yaw_sin * yaw_sin + yaw_cos * yaw_cos);
  const float vel_x = out_vel[down_grid_size * 0 + idx];
  const float vel_y = out_vel[down_grid_size * 1 + idx];

  det_boxes3d[idx].label = label;
  det_boxes3d[idx].score = yaw_norm >= yaw_norm_thresholds[label] ? max_score : 0.f;

  // If the score is 0, then we stop processing
  if (det_boxes3d[idx].score == 0.f) {
    return;
  }

  det_boxes3d[idx].x = x;
  det_boxes3d[idx].y = y;
  det_boxes3d[idx].z = z;
  det_boxes3d[idx].length = expf(l);
  det_boxes3d[idx].width = expf(w);
  det_boxes3d[idx].height = expf(h);
  det_boxes3d[idx].yaw = atan2f(yaw_sin, yaw_cos);
  det_boxes3d[idx].vel_x = vel_x;
  det_boxes3d[idx].vel_y = vel_y;

  if (has_variance) {
    const float offset_x_variance = out_offset[down_grid_size * 2 + idx];
    const float offset_y_variance = out_offset[down_grid_size * 3 + idx];
    const float z_variance = out_z[down_grid_size * 1 + idx];
    const float w_variance = out_dim[down_grid_size * 3 + idx];
    const float l_variance = out_dim[down_grid_size * 4 + idx];
    const float h_variance = out_dim[down_grid_size * 5 + idx];
    const float yaw_sin_log_variance = out_rot[down_grid_size * 2 + idx];
    const float yaw_cos_log_variance = out_rot[down_grid_size * 3 + idx];
    const float vel_x_variance = out_vel[down_grid_size * 2 + idx];
    const float vel_y_variance = out_vel[down_grid_size * 3 + idx];

    det_boxes3d[idx].x_variance = voxel_size_x * downsample_factor * expf(offset_x_variance);
    det_boxes3d[idx].y_variance = voxel_size_x * downsample_factor * expf(offset_y_variance);
    det_boxes3d[idx].z_variance = expf(z_variance);
    det_boxes3d[idx].length_variance = expf(l_variance);
    det_boxes3d[idx].width_variance = expf(w_variance);
    det_boxes3d[idx].height_variance = expf(h_variance);
    const float yaw_sin_sq = yaw_sin * yaw_sin;
    const float yaw_cos_sq = yaw_cos * yaw_cos;
    const float yaw_norm_sq = (yaw_sin_sq + yaw_cos_sq) * (yaw_sin_sq + yaw_cos_sq);
    det_boxes3d[idx].yaw_variance =
      (yaw_cos_sq * expf(yaw_sin_log_variance) + yaw_sin_sq * expf(yaw_cos_log_variance)) /
      yaw_norm_sq;
    det_boxes3d[idx].vel_x_variance = expf(vel_x_variance);
    det_boxes3d[idx].vel_y_variance = expf(vel_y_variance);
  }
}

void box3DToDetectedObject(
  const Box3D & box3d, const std::vector<std::string> & class_names, const bool has_twist,
  const bool has_variance, autoware_perception_msgs::msg::DetectedObject & obj)
{
  // TODO(yukke42): the value of classification confidence of DNN, not probability.
  obj.existence_probability = box3d.score;

  // classification
  autoware_perception_msgs::msg::ObjectClassification classification;
  classification.probability = 1.0f;
  if (box3d.label >= 0 && static_cast<size_t>(box3d.label) < class_names.size()) {
    classification.label = getSemanticType(class_names[box3d.label]);
  } else {
    classification.label = Label::UNKNOWN;
    RCLCPP_WARN_STREAM(
      rclcpp::get_logger("lidar_centerpoint"), "Unexpected label: UNKNOWN is set.");
  }

  if (autoware::object_recognition_utils::isCarLikeVehicle(classification.label)) {
    obj.kinematics.orientation_availability =
      autoware_perception_msgs::msg::DetectedObjectKinematics::SIGN_UNKNOWN;
  }

  obj.classification.emplace_back(classification);

  // pose and shape
  // mmdet3d yaw format to ros yaw format
  const float yaw = -box3d.yaw - autoware_utils::pi / 2;
  obj.kinematics.pose_with_covariance.pose.position =
    autoware_utils::create_point(box3d.x, box3d.y, box3d.z);
  obj.kinematics.pose_with_covariance.pose.orientation =
    autoware_utils::create_quaternion_from_yaw(yaw);
  obj.shape.type = autoware_perception_msgs::msg::Shape::BOUNDING_BOX;
  obj.shape.dimensions =
    autoware_utils::create_translation(box3d.length, box3d.width, box3d.height);
  if (has_variance) {
    obj.kinematics.has_position_covariance = has_variance;
    obj.kinematics.pose_with_covariance.covariance = convertPoseCovarianceMatrix(box3d);
  }

  // twist
  if (has_twist) {
    float vel_x = box3d.vel_x;
    float vel_y = box3d.vel_y;

    // twist of the object is based on the object coordinate system
    geometry_msgs::msg::Twist twist;
    twist.linear.x = std::cos(yaw) * vel_x + std::sin(yaw) * vel_y;
    twist.linear.y = -std::sin(yaw) * vel_x + std::cos(yaw) * vel_y;
    twist.angular.z = 0;  // angular velocity is not supported

    obj.kinematics.twist_with_covariance.twist = twist;
    obj.kinematics.has_twist = has_twist;
    if (has_variance) {
      obj.kinematics.has_twist_covariance = has_variance;
      obj.kinematics.twist_with_covariance.covariance = convertTwistCovarianceMatrix(box3d, yaw);
    }
  }
}

uint8_t getSemanticType(const std::string & class_name)
{
  if (class_name == "CAR") {
    return Label::CAR;
  } else if (class_name == "TRUCK") {
    return Label::TRUCK;
  } else if (class_name == "BUS") {
    return Label::BUS;
  } else if (class_name == "TRAILER") {
    return Label::TRAILER;
  } else if (class_name == "BICYCLE") {
    return Label::BICYCLE;
  } else if (class_name == "MOTORBIKE") {
    return Label::MOTORCYCLE;
  } else if (class_name == "PEDESTRIAN") {
    return Label::PEDESTRIAN;
  } else {
    return Label::UNKNOWN;
  }
}

inline bool isCarLikeVehicle(const uint8_t label)
{
  return label == ObjectClassification::BUS || label == ObjectClassification::CAR ||
         label == ObjectClassification::TRAILER || label == ObjectClassification::TRUCK;
}

geometry_msgs::msg::Quaternion create_quaternion_from_yaw(const double yaw)
{
  tf2::Quaternion q;
  q.setRPY(0, 0, yaw);
  return tf2::toMsg(q);
}

std::array<double, 36> convertPoseCovarianceMatrix(const Box3D & box3d)
{
  using POSE_IDX = autoware_utils::xyzrpy_covariance_index::XYZRPY_COV_IDX;
  std::array<double, 36> pose_covariance{};
  pose_covariance[POSE_IDX::X_X] = box3d.x_variance;
  pose_covariance[POSE_IDX::Y_Y] = box3d.y_variance;
  pose_covariance[POSE_IDX::Z_Z] = box3d.z_variance;
  pose_covariance[POSE_IDX::YAW_YAW] = box3d.yaw_variance;
  return pose_covariance;
}

std::array<double, 36> convertTwistCovarianceMatrix(const Box3D & box3d, const float yaw)
{
  using POSE_IDX = autoware_utils::xyzrpy_covariance_index::XYZRPY_COV_IDX;

  // twist covariance matrix is based on the object coordinate system
  std::array<double, 36> twist_covariance{};
  const float cos_yaw = std::cos(yaw);
  const float sin_yaw = std::sin(yaw);
  twist_covariance[POSE_IDX::X_X] =
    box3d.vel_x_variance * cos_yaw * cos_yaw + box3d.vel_y_variance * sin_yaw * sin_yaw;
  twist_covariance[POSE_IDX::X_Y] =
    (box3d.vel_y_variance - box3d.vel_x_variance) * sin_yaw * cos_yaw;
  twist_covariance[POSE_IDX::Y_X] = twist_covariance[POSE_IDX::X_Y];
  twist_covariance[POSE_IDX::Y_Y] =
    box3d.vel_x_variance * sin_yaw * sin_yaw + box3d.vel_y_variance * cos_yaw * cos_yaw;
  return twist_covariance;
}

std::vector<DetectedObject> NonMaximumSuppression::apply(
  const std::vector<DetectedObject> & input_objects)
{
  Eigen::MatrixXd iou_matrix = generateIoUMatrix(input_objects);

  std::vector<DetectedObject> output_objects;
  output_objects.reserve(input_objects.size());
  for (std::size_t i = 0; i < input_objects.size(); ++i) {
    const auto value = iou_matrix.row(i).maxCoeff();

    if (value <= params_.iou_threshold_) {
      output_objects.emplace_back(input_objects.at(i));
    }
  }

  return output_objects;
}

Eigen::MatrixXd NonMaximumSuppression::generateIoUMatrix(
  const std::vector<DetectedObject> & input_objects)
{
  // NOTE: row = target objects to be suppressed, col = source objects to be compared
  Eigen::MatrixXd triangular_matrix =
    Eigen::MatrixXd::Zero(input_objects.size(), input_objects.size());
  for (std::size_t target_i = 0; target_i < input_objects.size(); ++target_i) {
    for (std::size_t source_i = 0; source_i < target_i; ++source_i) {
      const auto & target_obj = input_objects.at(target_i);
      const auto & source_obj = input_objects.at(source_i);
      if (!isTargetPairObject(target_obj, source_obj)) {
        continue;
      }

      const double iou = autoware::object_recognition_utils::get2dIoU(target_obj, source_obj);
      triangular_matrix(target_i, source_i) = iou;
      // NOTE: If the target object has any objects with iou > iou_threshold, it
      // will be suppressed regardless of later results.
      if (iou > params_.iou_threshold_) {
        break;
      }
    }
  }

  return triangular_matrix;
}

bool NonMaximumSuppression::isTargetPairObject(
  const DetectedObject & object1, const DetectedObject & object2)
{
  const auto label1 =
    autoware::object_recognition_utils::getHighestProbLabel(object1.classification);
  const auto label2 =
    autoware::object_recognition_utils::getHighestProbLabel(object2.classification);

  // if labels are not the same, and one of them is pedestrian, do not suppress
  if (label1 != label2 && (label1 == Label::PEDESTRIAN || label2 == Label::PEDESTRIAN)) {
    return false;
  }

  const auto sqr_dist_2d = autoware_utils::calc_squared_distance2d(
    autoware::object_recognition_utils::getPose(object1),
    autoware::object_recognition_utils::getPose(object2));
  return sqr_dist_2d <= search_distance_2d_sq_;
}

inline std::uint8_t getHighestProbLabel(
  const std::vector<ObjectClassification> & object_classifications)
{
  return getHighestProbClassification(object_classifications).label;
}

inline ObjectClassification getHighestProbClassification(
  const std::vector<ObjectClassification> & object_classifications)
{
  if (object_classifications.empty()) {
    return ObjectClassification{};
  }
  return *std::max_element(
    std::begin(object_classifications), std::end(object_classifications),
    [](const auto & a, const auto & b) { return a.probability < b.probability; });
}

double calc_squared_distance2d(const Point1 & point1, const Point2 & point2)
{
  const auto p1 = get_point(point1);
  const auto p2 = get_point(point2);
  const auto dx = p1.x - p2.x;
  const auto dy = p1.y - p2.y;
  return dx * dx + dy * dy;
}

geometry_msgs::msg::Point get_point(const T & p)
{
  return geometry_msgs::build<geometry_msgs::msg::Point>().x(p.x).y(p.y).z(p.z);
}

double get2dIoU(
  const T1 & source_object, const T2 & target_object, const double min_union_area = 0.01)
{
  const auto source_polygon = autoware_utils_geometry::to_polygon2d(source_object);
  if (boost::geometry::area(source_polygon) < MIN_AREA) return 0.0;
  const auto target_polygon = autoware_utils_geometry::to_polygon2d(target_object);
  if (boost::geometry::area(target_polygon) < MIN_AREA) return 0.0;

  const double intersection_area = getIntersectionArea(source_polygon, target_polygon);
  if (intersection_area < MIN_AREA) return 0.0;
  const double union_area = getUnionArea(source_polygon, target_polygon);

  const double iou =
    union_area < min_union_area ? 0.0 : std::min(1.0, intersection_area / union_area);
  return iou;
}

Polygon2d to_polygon2d(
  const geometry_msgs::msg::Pose & pose, const autoware_perception_msgs::msg::Shape & shape)
{
  Polygon2d polygon;

  if (shape.type == autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    const auto point0 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point1 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point2 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point3 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;

    append_point_to_polygon(polygon, point0);
    append_point_to_polygon(polygon, point1);
    append_point_to_polygon(polygon, point2);
    append_point_to_polygon(polygon, point3);
  } else if (shape.type == autoware_perception_msgs::msg::Shape::CYLINDER) {
    const double radius = shape.dimensions.x / 2.0;
    constexpr int circle_discrete_num = 6;
    for (int i = 0; i < circle_discrete_num; ++i) {
      geometry_msgs::msg::Point point;
      point.x = std::cos(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.x;
      point.y = std::sin(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.y;
      append_point_to_polygon(polygon, point);
    }
  } else if (shape.type == autoware_perception_msgs::msg::Shape::POLYGON) {
    const double poly_yaw = tf2::getYaw(pose.orientation);
    const auto rotated_footprint = rotate_polygon(shape.footprint, poly_yaw);
    for (const auto rel_point : rotated_footprint.points) {
      geometry_msgs::msg::Point abs_point;
      abs_point.x = pose.position.x + rel_point.x;
      abs_point.y = pose.position.y + rel_point.y;

      append_point_to_polygon(polygon, abs_point);
    }
  } else {
    throw std::logic_error("The shape type is not supported in autoware_utils.");
  }

  // NOTE: push back the first point in order to close polygon
  if (!polygon.outer().empty()) {
    append_point_to_polygon(polygon, polygon.outer().front());
  }

  return is_clockwise(polygon) ? polygon : inverse_clockwise(polygon);
}

  using autoware_utils_geometry::calc_offset_pose;
  Polygon2d polygon;
  const auto point0 = calc_offset_pose(base_link_pose, base_to_front, width / 2.0, 0.0).position;
  const auto point1 = calc_offset_pose(base_link_pose, base_to_front, -width / 2.0, 0.0).position;
  const auto point2 = calc_offset_pose(base_link_pose, -base_to_rear, -width / 2.0, 0.0).position;
  const auto point3 = calc_offset_pose(base_link_pose, -base_to_rear, width / 2.0, 0.0).position;

  append_point_to_polygon(polygon, point0);
  append_point_to_polygon(polygon, point1);
  append_point_to_polygon(polygon, point2);
  append_point_to_polygon(polygon, point3);
  append_point_to_polygon(polygon, point0);

  return is_clockwise(polygon) ? polygon : inverse_clockwise(polygon);
}

double get_area(const autoware_perception_msgs::msg::Shape & shape)
{
  if (shape.type == autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    return get_rectangle_area(shape.dimensions);
  } else if (shape.type == autoware_perception_msgs::msg::Shape::CYLINDER) {
    return get_circle_area(shape.dimensions);
  } else if (shape.type == autoware_perception_msgs::msg::Shape::POLYGON) {
    return get_polygon_area(shape.footprint);
  }

  throw std::logic_error("The shape type is not supported in autoware_utils.");
}

void append_point_to_polygon(Polygon2d & polygon, const geometry_msgs::msg::Point & geom_point)
{
  Point2d point;
  point.x() = geom_point.x;
  point.y() = geom_point.y;

  bg::append(polygon.outer(), point);
}

geometry_msgs::msg::Polygon rotate_polygon(
  const geometry_msgs::msg::Polygon & polygon, const double & angle)
{
  const double cos = std::cos(angle);
  const double sin = std::sin(angle);
  geometry_msgs::msg::Polygon rotated_polygon;
  for (const auto & point : polygon.points) {
    auto rotated_point = point;
    rotated_point.x = cos * point.x - sin * point.y;
    rotated_point.y = sin * point.x + cos * point.y;
    rotated_polygon.points.push_back(rotated_point);
  }
  return rotated_polygon;
}

bool is_clockwise(const Polygon2d & polygon)
{
  const int n = polygon.outer().size();
  const double x_offset = polygon.outer().at(0).x();
  const double y_offset = polygon.outer().at(0).y();
  double sum = 0.0;
  for (std::size_t i = 0; i < polygon.outer().size(); ++i) {
    sum +=
      (polygon.outer().at(i).x() - x_offset) * (polygon.outer().at((i + 1) % n).y() - y_offset) -
      (polygon.outer().at(i).y() - y_offset) * (polygon.outer().at((i + 1) % n).x() - x_offset);
  }

  return sum < 0.0;
}

Polygon2d to_polygon2d(
  const geometry_msgs::msg::Pose & pose, const autoware_perception_msgs::msg::Shape & shape)
{
  Polygon2d polygon;

  if (shape.type == autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    const auto point0 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point1 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point2 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point3 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;

    append_point_to_polygon(polygon, point0);
    append_point_to_polygon(polygon, point1);
    append_point_to_polygon(polygon, point2);
    append_point_to_polygon(polygon, point3);
  } else if (shape.type == autoware_perception_msgs::msg::Shape::CYLINDER) {
    const double radius = shape.dimensions.x / 2.0;
    constexpr int circle_discrete_num = 6;
    for (int i = 0; i < circle_discrete_num; ++i) {
      geometry_msgs::msg::Point point;
      point.x = std::cos(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.x;
      point.y = std::sin(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.y;
      append_point_to_polygon(polygon, point);
    }
  } else if (shape.type == autoware_perception_msgs::msg::Shape::POLYGON) {
    const double poly_yaw = tf2::getYaw(pose.orientation);
    const auto rotated_footprint = rotate_polygon(shape.footprint, poly_yaw);
    for (const auto rel_point : rotated_footprint.points) {
      geometry_msgs::msg::Point abs_point;
      abs_point.x = pose.position.x + rel_point.x;
      abs_point.y = pose.position.y + rel_point.y;

      append_point_to_polygon(polygon, abs_point);
    }
  } else {
    throw std::logic_error("The shape type is not supported in autoware_utils.");
  }

  // NOTE: push back the first point in order to close polygon
  if (!polygon.outer().empty()) {
    append_point_to_polygon(polygon, polygon.outer().front());
  }

  return is_clockwise(polygon) ? polygon : inverse_clockwise(polygon);
}

inline double getIntersectionArea(
  const Polygon2d & source_polygon, const Polygon2d & target_polygon)
{
  std::vector<Polygon2d> intersection_polygons;
  boost::geometry::intersection(source_polygon, target_polygon, intersection_polygons);
  return getSumArea(intersection_polygons);
}

inline double getSumArea(const std::vector<Polygon2d> & polygons)
{
  return std::accumulate(
    polygons.begin(), polygons.end(), 0.0,
    [](double acc, const Polygon2d & p) { return acc + boost::geometry::area(p); });
}

inline double getUnionArea(const Polygon2d & source_polygon, const Polygon2d & target_polygon)
{
  std::vector<Polygon2d> union_polygons;
  boost::geometry::union_(source_polygon, target_polygon, union_polygons);
  return getSumArea(union_polygons);
}

inline double getSumArea(const std::vector<Polygon2d> & polygons)
{
  return std::accumulate(
    polygons.begin(), polygons.end(), 0.0,
    [](double acc, const Polygon2d & p) { return acc + boost::geometry::area(p); });
}

void DetectionClassRemapper::mapClasses(autoware_perception_msgs::msg::DetectedObjects & msg)
{
  for (auto & object : msg.objects) {
    const float bev_area = object.shape.dimensions.x * object.shape.dimensions.y;

    for (auto & classification : object.classification) {
      auto & label = classification.label;

      for (int i = 0; i < num_labels_; ++i) {
        if (
          allow_remapping_by_area_matrix_(label, i) && bev_area >= min_area_matrix_(label, i) &&
          bev_area <= max_area_matrix_(label, i)) {
          label = i;
          break;
        }
      }
    }
  }
}

  Eigen::Matrix<bool, Eigen::Dynamic, Eigen::Dynamic> allow_remapping_by_area_matrix_;
  Eigen::MatrixXd min_area_matrix_;
  Eigen::MatrixXd max_area_matrix_;
  int num_labels_;
};

